# R Code Skeleton

```R
library(rstan)
library(rstanarm)
library(ggplot2)
library(dplyr)

# ---------------------------------------------------------
# 1. Data Preparation
# ---------------------------------------------------------
# Assuming 'df' contains: day, daily_cases, intervention_status (0/1)
# N = 5000
# gamma = 1 / mean_infectious_period
# incubation_dist = Gamma parameters (shape, rate)

# ---------------------------------------------------------
# 2. Stan Model Definition (Negative Binomial SIR)
# ---------------------------------------------------------
stan_code <- "
data {
  int<lower=0> N;              // Population size
  int<lower=0> T;              // Number of time steps
  int<lower=0> cases[T];       // Observed daily cases
  int<lower=0,upper=1> intervention[T]; // 1 if intervention active
  real<lower=0> gamma;         // Recovery rate
  real<lower=0> inc_shape;     // Incubation shape
  real<lower=0> inc_rate;      // Incubation rate
}

parameters {
  real<lower=0> beta_0;        // Baseline transmission rate
  real<lower=0,upper=1> epsilon; // Intervention efficacy
  real<lower=0> theta;         // Overdispersion parameter (NB)
  real<lower=0> I_0;           // Initial infected
  real<lower=0> S_0;           // Initial susceptible
}

transformed parameters {
  vector[T] incidence;         // True incidence (new infections)
  vector[T] pred_cases;        // Predicted cases (convolved)

  // Simple SIR ODE integration (Euler method for skeleton)
  // In production, use ode_solver (e.g., rk45)
  real S = S_0;
  real I = I_0;
  real R = N - S - I;

  for (t in 1:T) {
    real beta_t = beta_0 * (1 - epsilon * intervention[t]);
    real new_infections = beta_t * S * I / N;

    incidence[t] = new_infections;

    // Update compartments
    S = S - new_infections;
    I = I + new_infections - gamma * I;
    R = R + gamma * I;

    // Convolve incidence with incubation distribution (simplified)
    // Note: Full convolution requires a loop over past days
    real expected = 0;
    for (k in 1:t) {
      real prob = gamma_pdf(k - 1, inc_shape, inc_rate); // Approximation
      expected += incidence[k] * prob;
    }
    pred_cases[t] = expected;
  }
}

model {
  // Priors
  beta_0 ~ normal(0.3, 0.1);
  epsilon ~ beta(1, 1);
  theta ~ cauchy(0, 2);
  I_0 ~ gamma(1, 1);
  S_0 ~ gamma(N, 1);

  // Likelihood
  cases ~ neg_binomial_2(pred_cases, theta);
}

generated quantities {
  vector[T] R_t;
  vector[T] smoothed_incidence;

  // Sliding window for R_t estimation
  int window = 7;
  for (t in window:T) {
    real sum_recent = 0;
    for (k in 0:(window-1)) {
      sum_recent += pred_cases[t-k];
    }
    smoothed_incidence[t] = sum_recent / window;

    // R_t calculation (simplified ratio)
    if (t > 1) {
      R_t[t] = smoothed_incidence[t] / smoothed_incidence[t-1];
    } else {
      R_t[t] = 1.0;
    }
  }
}
"

# ---------------------------------------------------------
# 3. Model Fitting
# ---------------------------------------------------------
fit_data <- list(
  N = 5000,
  T = nrow(df),
  cases = df$daily_cases,
  intervention = df$intervention_status,
  gamma = 1/7, # Example: 7 days infectious period
  inc_shape = 2.5,
  inc_rate = 0.5
)

# Fit using rstan (requires compilation)
fit <- stan(
  model_code = stan_code,
  data = fit_data,
  iter = 2000,
  chains = 4,
  cores = 4,
  control = list(adapt_delta = 0.95)
)

# ---------------------------------------------------------
# 4. Post-Processing and Rt Extraction
# ---------------------------------------------------------
# Extract posterior samples for R_t
R_samples <- extract(fit, pars = "R_t")$R_t

# Calculate mean and 95% CI for R_t
R_summary <- data.frame(
  day = df$day,
  R_mean = apply(R_samples, 2, mean),
  R_lower = apply(R_samples, 2, quantile, 0.025),
  R_upper = apply(R_samples, 2, quantile, 0.975)
)

# Plotting
ggplot(R_summary, aes(x = day)) +
  geom_line(aes(y = R_mean), color = "blue", size = 1) +
  geom_ribbon(aes(ymin = R_lower, ymax = R_upper), alpha = 0.2, fill = "blue") +
  geom_hline(yintercept = 1, linetype = "dashed", color = "red") +
  labs(title = "Time-Varying Reproduction Number (Rt)",
       x = "Day", y = "Rt") +
  theme_minimal()
```
